SELECT * FROM b_outbound_order


        AND (INSTR(outbound_order_no, #{query.searchWord}) OR INSTR(project_name, #{query.searchWord}) OR INSTR(receiver_name, #{query.searchWord}))


        AND INSTR(outbound_order_no, #{query.outboundOrderNo})


        AND INSTR(project_name, #{query.projectName})


        AND outbound_type = #{query.outboundType}


        AND approval_status = #{query.approvalStatus}


        AND status = #{query.status}


        AND deleted_flag = #{query.deletedFlag}


        AND create_user_id = #{query.createUserId}



    ORDER BY outbound_order_id DESC

SELECT * FROM b_outbound_order
WHERE outbound_order_no = #{outboundOrderNo}
LIMIT 1

SELECT * FROM b_outbound_order_item
WHERE outbound_order_id = #{outboundOrderId}
ORDER BY outbound_order_item_id ASC
